import { Component } from '@angular/core';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';
import { Router } from '@angular/router';
import { ContestationService } from '../../services/contestation.service';
import { CreateContestationResponse } from '../../models/contestation.model';

@Component({
  selector: 'app-new-contestation',
  templateUrl: './new-contestation.component.html'
})
export class NewContestationComponent {
  form: FormGroup;
  loading = false;
  successResponse: CreateContestationResponse | null = null;
  errorMsg = '';

  constructor(
    private fb: FormBuilder,
    private contestationService: ContestationService,
    private router: Router
  ) {
    this.form = this.fb.group({
      contestationId: ['', [Validators.required, Validators.minLength(3)]],
      description: [''],
      amount: [''],
      channel: ['']
    });
  }

  get f() { return this.form.controls; }

  onSubmit(): void {
    if (this.form.invalid) {
      this.form.markAllAsTouched();
      return;
    }

    this.loading = true;
    this.errorMsg = '';
    this.successResponse = null;

    const { contestationId, description, amount, channel } = this.form.value;

    const payload = {
      contestationId,
      ...(description && { description }),
      ...(amount && { amount: Number(amount) }),
      ...(channel && { channel })
    };

    this.contestationService.createContestation(payload).subscribe({
      next: (response) => {
        this.successResponse = response;
        this.loading = false;
      },
      error: (err) => {
        this.errorMsg = err.error?.message || 'Erro ao criar contestação. Verifique os dados.';
        this.loading = false;
      }
    });
  }

  viewDetail(requestId: string): void {
    this.router.navigate(['/contestations', requestId]);
  }

  newContestation(): void {
    this.form.reset();
    this.successResponse = null;
    this.errorMsg = '';
  }

  getStatusClass(status: string): string {
    const map: Record<string, string> = {
      'EM_ANDAMENTO': 'badge-em-andamento',
      'SUCESSO': 'badge-sucesso',
      'CANCELADO': 'badge-cancelado',
      'CALLBACK_FALHA': 'badge-callback-falha'
    };
    return map[status] || '';
  }
}
<div class="page-content">
  <div class="page-title">
    <span>📋</span> Nova Contestação
  </div>

  <!-- Formulário -->
  <div class="card" *ngIf="!successResponse">
    <div class="card-header">
      <h2>📝 Dados da Contestação</h2>
      <span class="badge badge-em-andamento">CONTESTACAO_ABERTA</span>
    </div>

    <div *ngIf="errorMsg" class="alert alert-danger">
      ⚠️ {{ errorMsg }}
    </div>

    <form [formGroup]="form" (ngSubmit)="onSubmit()">
      <!-- Linha 1: contestationId -->
      <div class="form-group">
        <label>Contestation ID <span class="required">*</span></label>
        <input
          type="text"
          class="form-control"
          formControlName="contestationId"
          placeholder="Ex: CONT-123456"
        />
        <div class="error-msg" *ngIf="f['contestationId'].invalid && f['contestationId'].touched">
          <span *ngIf="f['contestationId'].errors?.['required']">Contestation ID é obrigatório</span>
          <span *ngIf="f['contestationId'].errors?.['minlength']">Mínimo 3 caracteres</span>
        </div>
      </div>

      <!-- Linha 3: Dados opcionais -->
      <div class="form-row">
        <div class="form-group">
          <label>Descrição</label>
          <input
            type="text"
            class="form-control"
            formControlName="description"
            placeholder="Motivo da contestação"
          />
        </div>

        <div class="form-group">
          <label>Valor (R$)</label>
          <input
            type="number"
            class="form-control"
            formControlName="amount"
            placeholder="0.00"
            step="0.01"
          />
        </div>

        <div class="form-group">
          <label>Canal</label>
          <select class="form-control" formControlName="channel">
            <option value="">Selecione...</option>
            <option value="APP">App Mobile</option>
            <option value="WEB">Internet Banking</option>
            <option value="ATM">Caixa Eletrônico</option>
            <option value="BRANCH">Agência</option>
          </select>
        </div>
      </div>

      <!-- Type (readonly) -->
      <div class="form-group">
        <label>Tipo de Comunicação</label>
        <input type="text" class="form-control" value="CONTESTACAO_ABERTA" disabled />
        <small class="text-muted">Tipo fixo conforme regras de negócio.</small>
      </div>

      <div class="d-flex gap-2 mt-2">
        <button type="submit" class="btn btn-primary" [disabled]="loading">
          <span *ngIf="loading" class="spinner"></span>
          <span *ngIf="!loading">🚀</span>
          {{ loading ? 'Enviando...' : 'Criar Contestação' }}
        </button>
        <button type="button" class="btn btn-secondary" (click)="form.reset()" [disabled]="loading">
          🔄 Limpar
        </button>
      </div>
    </form>
  </div>

  <!-- Sucesso -->
  <div class="card" *ngIf="successResponse">
    <div class="card-header">
      <h2>✅ Contestação Criada!</h2>
      <span class="badge" [class]="successResponse.idempotent ? 'badge-em-andamento' : 'badge-sucesso'">
        {{ successResponse.idempotent ? '⚡ IDEMPOTENTE' : '✅ NOVO' }}
      </span>
    </div>

    <div class="alert alert-success" *ngIf="!successResponse.idempotent">
      ✅ Contestação criada com sucesso e enfileirada para processamento!
    </div>

    <div class="alert alert-warning" *ngIf="successResponse.idempotent">
      ⚡ Contestação já existia. Retornando a contestação existente (idempotência).
    </div>

    <div class="detail-grid mt-2">
      <div class="detail-item">
        <span class="label">Request ID</span>
        <span class="value text-mono">{{ successResponse.requestId }}</span>
      </div>
      <div class="detail-item">
        <span class="label">Status</span>
        <span class="badge" [ngClass]="getStatusClass(successResponse.status)">
          {{ successResponse.status }}
        </span>
      </div>
      <div class="detail-item">
        <span class="label">Correlation ID</span>
        <span class="value text-mono">{{ successResponse.correlationId }}</span>
      </div>
      <div class="detail-item">
        <span class="label">Recebido em</span>
        <span class="value">{{ successResponse.receivedAt | date:'dd/MM/yyyy HH:mm:ss' }}</span>
      </div>
    </div>

    <div class="d-flex gap-2 mt-3">
      <button class="btn btn-primary" (click)="viewDetail(successResponse.requestId)">
        🔍 Ver Detalhes
      </button>
      <button class="btn btn-secondary" (click)="newContestation()">
        ➕ Nova Contestação
      </button>
    </div>
  </div>
</div>
